INSERT INTO quiz_question (id, vocabulary_word_id, target_level, contextual_cloze, translation, correct_option, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('22b0cf5e-6bad-5fb3-a740-f3d25ba4e371', '8b3242aa-721e-485b-a282-9f1917c6f65d', 'SENIOR_HIGH', 'He has ___ unique way of solving math problems.', '他有一種獨特的方法來解決數學問題。', 'a', 'some', 'any', 'each', 'a 為不定冠詞，用於單數可數名詞前，表示「一種」。', 'a 代表 one (一個)。', '2026-07-05 09:30:25', '2026-07-05 09:30:25'),
('bac1ef16-97f8-514d-adee-331c7b5e70ad', '91dcf5ec-a9de-490b-a4f5-84248a8f2fa9', 'SENIOR_HIGH', 'Even though the scientist faced numerous setbacks, ___ never gave up on his groundbreaking research.', '儘管這位科學家面臨了多次挫折，他從未放棄過他那開創性的研究。', 'he', 'she', 'we', 'they', '代名詞，用來代替前面提到的男性名詞。', '看到 his (他的) → 主詞使用 he。', '2026-07-06 10:50:11', '2026-07-06 10:50:11'),
('82115e03-ae4d-57c2-9d82-97a8d3f420f5', '24837458-0d4f-4a59-9dc7-ae944f0f278c', 'SENIOR_HIGH', 'The main difficulty in learning a new language ___ mastering its grammar.', '學習一門新語言的主要困難在於掌握其語法。', 'is', 'has', 'does', 'says', 'be 動詞的第三人稱單數現在式', 'is 代表「是」或「在」，用於描述主詞的狀態或身分。', '2026-07-05 10:10:22', '2026-07-05 10:10:22'),
('2ed8ab6e-d872-56e3-ab34-317ca4bd2c2d', 'da922e1c-b794-4edf-807f-467df6cbb4eb', 'SENIOR_HIGH', 'He is the ___ and only survivor of the tragic plane crash.', '他是那場悲慘空難中唯一的倖存者。', 'one', 'last', 'best', 'most', 'one and only 是一個固定片語，意為「唯一的、獨一無二的」。', 'one and only → 只有這一個，獨一無二。', '2026-07-06 10:53:26', '2026-07-06 10:53:26'),
('4776940f-21e3-5d5f-a238-c8cf165970a1', 'da922e1c-b794-4edf-807f-467df6cbb4eb', 'SENIOR_HIGH', '___ of the team members was injured during the intense football game.', '團隊成員中有一人在激烈的足球比賽中受傷了。', 'one', 'all', 'many', 'several', 'one 在此作為代名詞，指代團隊中的其中一人；注意動詞用 was，故須選單數代名詞。', 'one of + 複數名詞 + 單數動詞 → 其中的一個。', '2026-07-06 10:53:26', '2026-07-06 10:53:26'),
('753527cb-9dc9-52d4-b92b-1ca5c504fcdd', '1d86e27e-0866-4c5e-8277-4bc91cc8ab5e', 'SENIOR_HIGH', 'I didn''t realize the problem was ___ serious.', '我沒意識到問題有那麼嚴重。', 'that', 'very', 'so', 'too', '副詞 (adv.)，用於否定句中，表示「那麼」或「那樣地」。', 'That (那麼) → 表示程度的強調。', '2026-07-05 14:26:52', '2026-07-05 14:26:52'),
('d6a30862-b197-5b9a-83ec-36c616b005f1', '8fecc1f7-8571-4e65-874e-7bec724d9609', 'SENIOR_HIGH', '___ sun rises in the east every morning.', '太陽每天早晨從東方升起。', 'The', 'A', 'Some', 'Any', '定冠詞 (Definite Article)', '獨一無二的事物用 the', '2026-07-05 10:22:35', '2026-07-05 10:22:35');
